protected void new()
{
    super(classStr(KPMGCommon_SalesPrintWayBillService), methodStr(KPMGCommon_SalesPrintWayBillService, process), SysOperationExecutionMode::Synchronous); //¿Qué modo de ejecución queremos?
}

public ClassDescription defaultCaption()
{
    return "@KPMGCommon:PrintWayBill"; //Imprimir Carta de porte
}

public static KPMGCommon_SalesPrintWayBillController construct(SysOperationExecutionMode _executionMode = SysOperationExecutionMode::Synchronous)
{
    KPMGCommon_SalesPrintWayBillController controller;
    controller = new KPMGCommon_SalesPrintWayBillController();
    controller.parmExecutionMode(_executionMode);
    controller.parmShowDialog(false);
    return controller;
}

public static void main (Args _args)
{
    KPMGCommon_SalesPrintWayBillContract    contract;
    KPMGCommon_SalesPrintWayBillController  controller;
    CustPackingSlipJour                     custPackingSlipJour;

    controller = KPMGCommon_SalesPrintWayBillController::construct();
    controller.parmArgs(_args);
    custPackingSlipJour = _args.record();
    contract = controller.getDataContractObject();
    contract.parmCustPackingSlipJour(custPackingSlipJour);
    controller.startOperation();
}
